values = [5, 10, 15]
for val in values:
    stack.push(val)
print('Stack after push:', stack.to_list())
popped = stack.pop()
print('Popped item:', popped)
print('Stack after pop:', stack.to_list())
print('Top item (peek):', stack.peek())
