#include <stdio.h>
#include <stdlib.h>
#define MAX_SIZE 100

typedef struct Stack {
    int items[MAX_SIZE];
    int top;
} Stack;

void initStack(Stack* stack) {
    stack->top = -1;
}

void push(Stack* stack, int item) {
    if (stack->top < MAX_SIZE - 1) {
        stack->items[++stack->top] = item;
    }
}

int pop(Stack* stack) {
    if (!isEmpty(stack)) {
        return stack->items[stack->top--];
    }
    return -1;
}

int peek(Stack* stack) {
    if (!isEmpty(stack)) {
        return stack->items[stack->top];
    }
    return -1;
}

int isEmpty(Stack* stack) {
    return stack->top == -1;
}

void printStack(Stack* stack) {
    printf("[");
    for (int i = 0; i <= stack->top; i++) {
        printf("%d", stack->items[i]);
        if (i < stack->top) printf(", ");
    }
    printf("]\n");
}

int main() {
    Stack stack;
    initStack(&stack);
    int values[] = {5, 10, 15};
    for (int i = 0; i < 3; i++) {
        push(&stack, values[i]);
    }
    printf("Stack after push: ");
    printStack(&stack);
    int popped = pop(&stack);
    printf("Popped item: %d\n", popped);
    printf("Stack after pop: ");
    printStack(&stack);
    printf("Top item (peek): %d\n", peek(&stack));
    return 0;
}
// Output: Stack after push: [5, 10, 15]
// Output: Popped item: 15
// Output: Stack after pop: [5, 10]
// Output: Top item (peek): 10

