using System;
using System.Collections.Generic;

class Stack {
    private List<int> items;

    public Stack() {
        items = new List<int>();
    }

    public void Push(int item) {
        items.Add(item);
    }

    public int? Pop() {
        if (!IsEmpty()) {
            int item = items[items.Count - 1];
            items.RemoveAt(items.Count - 1);
            return item;
        }
        return null;
    }

    public int? Peek() {
        if (!IsEmpty()) {
            return items[items.Count - 1];
        }
        return null;
    }

    public bool IsEmpty() {
        return items.Count == 0;
    }

    public List<int> ToList() {
        return new List<int>(items);
    }
}

class Program {
    static void Main() {
        Stack stack = new Stack();
        int[] values = { 5, 10, 15 };
        foreach (var val in values) {
            stack.Push(val);
        }
        Console.WriteLine("Stack after push: [" + string.Join(", ", stack.ToList()) + "]");
        int? popped = stack.Pop();
        Console.WriteLine("Popped item: " + popped);
        Console.WriteLine("Stack after pop: [" + string.Join(", ", stack.ToList()) + "]");
        Console.WriteLine("Top item (peek): " + stack.Peek());
    }
}
// Output: Stack after push: [5, 10, 15]
// Output: Popped item: 15
// Output: Stack after pop: [5, 10]
