#include <iostream>
#include <vector>

class Stack {
private:
    std::vector<int> items;

public:
    void push(int item) {
        items.push_back(item);
    }

    int pop() {
        if (!isEmpty()) {
            int item = items.back();
            items.pop_back();
            return item;
        }
        return -1;
    }

    int peek() {
        if (!isEmpty()) {
            return items.back();
        }
        return -1;
    }

    bool isEmpty() {
        return items.empty();
    }

    std::vector<int> toVector() {
        return items;
    }
};

int main() {
    Stack stack;
    int values[] = {5, 10, 15};
    for (int val : values) {
        stack.push(val);
    }
    std::cout << "Stack after push: [";
    auto result = stack.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    int popped = stack.pop();
    std::cout << "Popped item: " << popped << "\n";
    std::cout << "Stack after pop: [";
    result = stack.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    std::cout << "Top item (peek): " << stack.peek() << "\n";
    return 0;
}
// Output: Stack after push: [5, 10, 15]
// Output: Popped item: 15
// Output: Stack after pop: [5, 10]
